const playbookRaw = String($items('Extrair Texto Manual')[0]?.json?.playbookText || '');
let playbookText = playbookRaw.replace(/\u0000/g, '').trim();
if (playbookText.length > 8000) playbookText = playbookText.slice(0, 8000);

const rawItems = $items('Listar Arquivos Contexto').map(i => i.json || {});
const hasDriveError = rawItems.some((it) => typeof it.error === 'string' && it.error.length > 0);
const files = hasDriveError
  ? []
  : rawItems.filter((f) => f.id || f.name || f.fileName || f.title || f.originalFilename);

const enriched = files
  .map((f) => {
    const name = f.name || f.fileName || f.title || f.originalFilename || '';
    const link = f.webViewLink || (f.id ? `https://drive.google.com/file/d/${f.id}/view` : '');
    return { name, link };
  })
  .filter((f) => f.name)
  .slice(0, 40);

const contextLines = enriched.map((f, idx) => `${idx + 1}. ${f.name}${f.link ? ` - ${f.link}` : ''}`);

const businessKnowledge = [
  'A Casaboni trabalha com acabamentos completos, nao apenas pisos.',
  'Solucoes principais: pisos vinilicos clicados, rodapes de poliestireno, telhas shingle e ripados WPC.',
  'Linhas de piso: Veneza, Verona, Florenca, Londres, Rio de Janeiro e Washington.',
  'Beneficios do piso vinilico: resistencia, prova d\'agua, limpeza pratica, instalacao facilitada e conforto termico/acustico.',
  'Rodapes disponiveis em 7cm e 10cm (liso, frisado e arredondado).',
  'Telhas shingle: alta durabilidade, baixa manutencao, isolamento termico/acustico, cores cinza e preto.',
  'Ripados WPC: acabamento sofisticado, resistentes e faceis de manter; opcoes Carvalho Ipe, Peroba Jatoba, Cerejeira e Nogueira.',
  'Contato institucional: www.casaboni.com.br, WhatsApp (55) 99178-0627, Instagram @casaboni_.',
  'Se pedirem fotos, compartilhar somente a categoria solicitada.'
];

const systemHints = [
  'Atendimento inicial Casaboni: objetivo, cordial e consultivo.',
  'Entender ambiente, metragem, estilo e prazo antes da recomendacao final.',
  'Nunca limitar a conversa apenas a pisos quando o cliente perguntar por outras solucoes.',
  ...businessKnowledge
];

const ragPromptContext = [
  playbookText ? 'Manual oficial do consultor (Drive):\n' + playbookText : 'Manual oficial do consultor indisponivel nesta requisicao.',
  '',
  'Base de conhecimento Casaboni (arquivos no Drive):',
  ...contextLines,
  '',
  'Resumo do portfolio e posicionamento:',
  ...businessKnowledge,
  '',
  'Diretrizes de atendimento:',
  ...systemHints
].join('\n');

return [{
  json: {
    ok: true,
    requestId: $('Normalizar Consulta').item.json.requestId,
    question: $('Normalizar Consulta').item.json.question,
    customerContext: $('Normalizar Consulta').item.json.customerContext,
    filesFound: enriched.length,
    driveCatalog: contextLines,
    playbookLoaded: Boolean(playbookText),
    driveError: hasDriveError ? (rawItems[0]?.error || 'Erro ao listar arquivos no Drive') : '',
    systemHints,
    ragPromptContext
  }
}];

